import { ColorRuleProps } from '../../../core/types/color-rule.js';
import { getColorPalette } from '../../../core/utils/get-color-palette.js';
import type {
  BarMetadata,
  DotMetadata,
  LineMetadata,
  SeriesToMetadata,
  XYChartSeriesWithDatapoints,
} from '../../types/xy-chart-internals.js';

export const applyColorRuleToSeriesMetadata = (
  seriesToMetadata: SeriesToMetadata,
  series: XYChartSeriesWithDatapoints,
  seriesMetadata: DotMetadata | LineMetadata | BarMetadata,
  rule: ColorRuleProps,
  index: number,
) => {
  const colorOverride = rule.colorPalette
    ? getColorPalette(seriesMetadata.name, index, rule.colorPalette)
    : { Default: rule.color };

  if (colorOverride) {
    seriesToMetadata.set(series, {
      ...seriesMetadata,
      color: colorOverride,
    });
  }
};
